import{_ as e,o as i,c as a,ag as t}from"./chunks/framework.BLeoozAw.js";const p="/Awesome-SRC-experience/img/1_jXuV7DEcDagNjxxVvFgH7g.jpg",r="/Awesome-SRC-experience/img/1_75Ki83rT7dkqlELXRcXrWQ.gif",h="/Awesome-SRC-experience/img/1_hEe7XtLKFmHUcCT52CCMLQ.jpg",n="/Awesome-SRC-experience/img/1_IN2KugF8Yh-EPyZG-LA5pg.jpg",o="/Awesome-SRC-experience/img/1_-pqAivs9hz4Z3MYkWBxypA.gif",l="/Awesome-SRC-experience/img/1_PYSZnqlqQ1zKkfF7Nob2Kw.gif",c="/Awesome-SRC-experience/img/1_WHyhjTvpF-Oxq00wrT_sOQ.gif",d="/Awesome-SRC-experience/img/1_0YxpmznY5qmwq1Aa6U9Zew.jpg",g="/Awesome-SRC-experience/img/1_qtiInA-eaOcryZyPezKhQA.jpg",k="/Awesome-SRC-experience/img/1_BzJ5E-s26m34uwV6awIKmg.gif",v=JSON.parse('{"title":"Tomcat 渗透测试：利用Apache Struts2 S2-016(CVE-2013-2251) 漏洞获得RCE","description":"Awesome SRC Experience - Tomcat 渗透测试：利用Apache Struts2 S2-016(CVE-2013-2251) 漏洞获得RCE","frontmatter":{"title":"Tomcat 渗透测试：利用Apache Struts2 S2-016(CVE-2013-2251) 漏洞获得RCE","description":"Awesome SRC Experience - Tomcat 渗透测试：利用Apache Struts2 S2-016(CVE-2013-2251) 漏洞获得RCE"},"headers":[],"relativePath":"experience/Web服务器/web-server-misconfig.md","filePath":"experience/Web服务器/web-server-misconfig.md"}'),m={name:"experience/Web服务器/web-server-misconfig.md"};function C(u,s,F,b,y,_){return i(),a("div",null,[...s[0]||(s[0]=[t('<h1 id="tomcat-渗透测试-利用apache-struts2-s2-016-cve-2013-2251-漏洞获得rce" tabindex="-1">Tomcat 渗透测试：利用Apache Struts2 S2-016(CVE-2013-2251) 漏洞获得RCE <a class="header-anchor" href="#tomcat-渗透测试-利用apache-struts2-s2-016-cve-2013-2251-漏洞获得rce" aria-label="Permalink to &quot;Tomcat 渗透测试：利用Apache Struts2 S2-016(CVE-2013-2251) 漏洞获得RCE&quot;">​</a></h1><p>在寻找可攻击的目标时，我总是优先考虑那些范围广泛、开放式的网站，因为它们能让我更自由地寻找匹配自身技能的资产。在决定攻击一个公开程序并完成子域名枚举后，我决定使用 Shodan 来查找该公司拥有的资产，并使用了以下查询语句：</p><div class="language-context vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">context</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>org:Company.Inc</span></span></code></pre></div><p>在经过一番探索后，我发现了一个引人注目的目标，决定对其进行攻击。选择该目标的原因是，我发现它开放了非标准端口，而且运行着 <strong>Tomcat/8.5.32</strong> 版本。</p><p><img src="'+p+'" alt=""></p><p>首先，我对IP地址进行了全面的端口扫描，并将扫描结果传递给 <code>httpx</code> 工具，以检查其提供的HTTP服务。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">naabu</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -host</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Pn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> portscan</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> httpx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -td</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -server</span></span></code></pre></div><p><img src="'+r+'" alt=""></p><p>令我惊讶的是，我发现了更多开放端口，其中一个新发现的端口运行着HTTP服务。</p><p><img src="'+h+'" alt=""></p><p>我发现端口 <code>8333</code> 运行着另一个版本的<code>Tomcat</code> 服务器，这是要给有趣的发现，让我们继续测试。首先，让我们使用<code>searchploit</code> 工具搜索与该版本相关的CVE漏洞。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">searchsploit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;tomcat 7&quot;</span></span></code></pre></div><p><img src="'+n+'" alt=""></p><p>遗憾的是，上述的漏洞里利用方法均未成功，包括针对 CVE-2017-12617 和 CVE-2020-1938 的攻击。 <img src="'+o+'" alt=""></p><p>回到主页后，我决定开始进行目录和文件模糊测试。首先，我使用默认字典列表尝试使用<code>dirsearch</code>工具。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dirsearch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://x.x.x.x:8333</span></span></code></pre></div><p>然而，除了<code>manager</code>和&#39;host-manager&#39;目录之外，我没有发现其他有趣的结果，这两个目录返回了401错误。因此，我决定使用<code>Hydra</code>工具尝试默认凭据。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hydra</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/tomcat-usernames</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -P</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/tomcat-passwords</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> x.x.x.x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8333</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /manager/html</span></span></code></pre></div><p>再次一无所获。</p><p><img src="'+l+'" alt=""></p><p>再次进行模糊测试，这次使用来自<a href="https://github.com/six2dez/OneListForAll" target="_blank" rel="noreferrer">GitHub - six2dez/OneListForAll</a> 的<code>shortlist</code> 词表。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dirsearch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://x.x.x.x:833</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">3&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/wordlist/OnelistForAll/onelistforallshort.txt</span></span></code></pre></div><p>这次我发现了一个新的目录<code>/sdp/&gt;&gt;302&gt;&gt;/sdp/validateUser.action</code>，其中包含一个登录表单。</p><p>因此，我立即开始测试是否存在SQL注入漏洞，但没有成功。然后我记起 CVE-2017-5638，所以我是用<code>nuclei</code>模板对该端点进行了测试，但仍然没有发现任何结果。</p><p><img src="'+c+'" alt=""></p><p>回到<code>/sdp/</code>端点之后的目录模糊测试中，这次我发现了一个新的目录：<code>/sdp/struts/webconsole.html?debug=console</code></p><p><img src="'+d+'" alt=""></p><p>那一刻，我非常高兴，以为自己找到了RCE（远程命令执行）漏洞。但随后，我又遇到了无数次的问题：控制台出现了大量JS错误，每次修复一个，另一个又出现。最后，我只能在OGNL（Object-Graph Navigation Language） 控制台中打印HTML代码，无法执行命令。</p><p>回到Burp Session的历史选项卡中，滚动浏览时，我发现了一个新文件：<code>showLogin.action</code>。出于绝望，我决定尝试一个我在搜索Apache Struts 2 和OGNL注入相关的实验室和文章时找到的有效负载。</p><p><img src="'+g+'" alt=""></p><p>该有效负载会在服务器上执行id命令。我将该负载添加到<code>showLogin.action</code> 并作为Get请求发送。突然，意想不到的事情发生了。当时我的反应是--&gt;</p><p><img src="'+k+'" alt=""></p><p>接下来，我将此问题报告给<code>BugCrowd</code>它们立即进行了分类，但该计划后来将其降级为P2，称其为旧资产，并通过删除IP来解决。</p><p>原文链接：<a href="https://medium.com/@yousefmoh15/how-i-got-rce-in-one-of-bugcrowds-public-programs-5725c8dc46ce" target="_blank" rel="noreferrer">https://medium.com/@yousefmoh15/how-i-got-rce-in-one-of-bugcrowds-public-programs-5725c8dc46ce</a></p><h1 id="使用的工具" tabindex="-1">使用的工具 <a class="header-anchor" href="#使用的工具" aria-label="Permalink to &quot;使用的工具&quot;">​</a></h1><ul><li>网络空间搜索引擎：<a href="https://www.shodan.io/" target="_blank" rel="noreferrer">Shodan</a></li><li>批量端口扫描神器：<a href="https://github.com/projectdiscovery/naabu" target="_blank" rel="noreferrer">Naabu</a></li><li>Web资产探测神器：<a href="https://github.com/projectdiscovery/httpx" target="_blank" rel="noreferrer">Httpx</a></li><li>开源漏洞利用程序数据库：<a href="https://www.exploit-db.com/searchsploit" target="_blank" rel="noreferrer">Exploit-DB</a></li><li>目录及文件模糊测试工具：<a href="https://github.com/maurosoria/dirsearch" target="_blank" rel="noreferrer">dirsearch</a></li><li>多协议密码破解神器：<a href="https://github.com/vanhauser-thc/thc-hydra" target="_blank" rel="noreferrer">THC Hydra</a></li><li>最受欢迎的开源漏扫工具：<a href="https://github.com/projectdiscovery/nuclei" target="_blank" rel="noreferrer">nuclei</a></li><li>Web安全测试神器：<a href="https://portswigger.net/burp" target="_blank" rel="noreferrer">Burp suite</a></li></ul><h2 id="复现步骤" tabindex="-1">复现步骤 <a class="header-anchor" href="#复现步骤" aria-label="Permalink to &quot;复现步骤&quot;">​</a></h2><p>(待完善)</p><h2 id="修复建议" tabindex="-1">修复建议 <a class="header-anchor" href="#修复建议" aria-label="Permalink to &quot;修复建议&quot;">​</a></h2><p>(待完善)</p>',40)])])}const f=e(m,[["render",C]]);export{v as __pageData,f as default};
